.darma-loader-darma-custom-398 {
  width: 92px;
  height: 60px;
  color: var(--loader-color, #db2777);
  --c: radial-gradient(farthest-side,currentColor 96%,#0000);
  background:var(--c) 100% 100% /30% 60%,var(--c) 70% 0 /50% 100%,var(--c) 0 100% /36% 68%,var(--c) 27% 18% /26% 40%,linear-gradient(currentColor 0 0) bottom/67% 58%;
  background-repeat: no-repeat;
  position: relative;
}.darma-loader-darma-custom-398:before {content: "";
  position: absolute;
  inset: 0;
  background: inherit;
  opacity: 0.4;
  animation: darma-loader-darma-custom-398-l7 1s infinite;
}@keyframes darma-loader-darma-custom-398-l7 {to {transform: scale(1.8);
  opacity:0}}

